import{_ as e,o,c as a,ag as r}from"./chunks/framework-C5-Jzrz4.js";const i=JSON.parse('{"title":"Cropper 图片裁剪","description":"@vben/common-ui 的图片裁剪组件，支持比例约束和裁剪结果导出","frontmatter":{"title":"Cropper 图片裁剪","description":"@vben/common-ui 的图片裁剪组件，支持比例约束和裁剪结果导出","outline":"deep","lastUpdated":true},"headers":[],"relativePath":"scripts/components/common-ui/cropper.md","filePath":"scripts/components/common-ui/cropper.md","lastUpdated":null}');const l=e({name:"scripts/components/common-ui/cropper.md"},[["render",function(e,i,l,c,t,d){return o(),a("div",null,[...i[0]||(i[0]=[r('<h1 id="vcropper" tabindex="-1"><code>VCropper</code> <a class="header-anchor" href="#vcropper" aria-label="Permalink to &quot;`VCropper`&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p><code>VCropper</code> 是项目内的图片裁剪组件，支持拖拽、缩放、固定比例和裁剪结果导出。</p><h2 id="适用范围" tabindex="-1">适用范围 <a class="header-anchor" href="#适用范围" aria-label="Permalink to &quot;适用范围&quot;">​</a></h2><ul><li>用户头像裁剪</li><li>图片上传后的二次处理</li><li>需要在前端直接导出裁剪图的场景</li></ul><h2 id="对应源码目录或关键文件" tabindex="-1">对应源码目录或关键文件 <a class="header-anchor" href="#对应源码目录或关键文件" aria-label="Permalink to &quot;对应源码目录或关键文件&quot;">​</a></h2><ul><li><code>packages/effects/common-ui/src/components/cropper/index.ts</code></li><li><code>packages/effects/common-ui/src/components/cropper/cropper.vue</code></li></ul><h2 id="核心机制" tabindex="-1">核心机制 <a class="header-anchor" href="#核心机制" aria-label="Permalink to &quot;核心机制&quot;">​</a></h2><h3 id="导出" tabindex="-1">导出 <a class="header-anchor" href="#导出" aria-label="Permalink to &quot;导出&quot;">​</a></h3><ul><li><code>VCropper</code></li></ul><h3 id="关键-props" tabindex="-1">关键 Props <a class="header-anchor" href="#关键-props" aria-label="Permalink to &quot;关键 Props&quot;">​</a></h3><ul><li><code>img</code>：裁剪源图片</li><li><code>width</code>：容器宽度</li><li><code>height</code>：容器高度</li><li><code>aspectRatio</code>：裁剪比例，格式为 <code>宽:高</code></li></ul><h3 id="暴露方法" tabindex="-1">暴露方法 <a class="header-anchor" href="#暴露方法" aria-label="Permalink to &quot;暴露方法&quot;">​</a></h3><ul><li><code>getCropImage(format?, quality?, outputType?, targetWidth?, targetHeight?)</code></li></ul><h3 id="实现特点" tabindex="-1">实现特点 <a class="header-anchor" href="#实现特点" aria-label="Permalink to &quot;实现特点&quot;">​</a></h3><ul><li>图片加载后自动计算适配尺寸。</li><li>裁剪框支持拖动和边角缩放。</li><li><code>getCropImage()</code> 可返回 <code>Blob</code> 或 base64 字符串。</li><li>远程图片会尝试处理跨域场景，避免 canvas 导出失败。</li></ul><h2 id="使用方式与注意事项" tabindex="-1">使用方式与注意事项 <a class="header-anchor" href="#使用方式与注意事项" aria-label="Permalink to &quot;使用方式与注意事项&quot;">​</a></h2><ul><li><code>aspectRatio</code> 只接受类似 <code>1:1</code>、<code>16:9</code> 的格式。</li><li><code>getCropImage()</code> 默认输出 <code>image/png</code>，质量参数会被限制在 <code>0~1</code>。</li><li>如果图片不支持跨域访问，导出阶段仍可能失败，这不是组件逻辑问题。</li></ul>',18)])])}]]);export{i as __pageData,l as default};
